// Generar un beep usando Web Audio API
let audioContext = null;

export function reproducirBeep(frecuencia = 800, duracion = 200) {
  try {
    if (!audioContext) audioContext = new (window.AudioContext || window.webkitAudioContext)();
    const oscillator = audioContext.createOscillator();
    const gainNode = audioContext.createGain();
    oscillator.connect(gainNode);
    gainNode.connect(audioContext.destination);
    oscillator.frequency.value = frecuencia;
    oscillator.type = 'sine';
    gainNode.gain.value = 0.3;
    oscillator.start();
    oscillator.stop(audioContext.currentTime + duracion / 1000);
  } catch {}
}

export function reproducirNotificacion() {
  reproducirBeep(800, 150);
  setTimeout(() => reproducirBeep(1000, 150), 200);
}

export function reproducirAlarmaSOS() {
  reproducirBeep(600, 300);
  setTimeout(() => reproducirBeep(800, 300), 400);
  setTimeout(() => reproducirBeep(600, 300), 800);
  setTimeout(() => reproducirBeep(800, 300), 1200);
}
